import base64, os

FILES = {
    "components/HardDeckPanel.tsx": """""",
    "components/SpinWheel.tsx": """""",
    "app/host/quiz/page.tsx": """""",
    "app/host/display/page.tsx": """""",
    "components/PlayerQuizScreen.tsx": """""",
    "supabase/sql/hard_deck.sql": """""",
}


for path, b64 in FILES.items():
    os.makedirs(os.path.dirname(path), exist_ok=True) if os.path.dirname(path) else None
    with open(path, "wb") as f:
        f.write(base64.b64decode(b64))
    print("Written:", path)
print("All Hard Deck files written successfully")
